def construct(N):
    """For each N, pick the AP circulant {r,r+d,...} minimizing Hoffman bound on alpha.
    AP offsets have diffs = multiples of d, not in S (since S ≡ r mod d, r≠0 mod d) => K4-free."""
    best_hc = float('inf')
    best_S = [2, 3, 5]

