                    sum(2 * math.cos(2 * math.pi * j * s / N) for s in S)
                    for j in range(1, N)
                )
                if lam_min >= 0:
                    continue
                hc = (-lam_min) * deg / ((deg - lam_min) * math.log(deg))
                if hc < best_hc:
                    best_hc = hc
                    best_S = S

    seen = set()
    edges = []
    for i in range(N):
        for s in best_S:
            for j in [(i + s) % N, (i - s) % N]:
                key = (min(i, j), max(i, j))
                if key not in seen and key[0] != key[1]:
