    # Find generator of GF(25)* (order 24) by trying candidates
    def order(g):
        x = g; n = 1
        while x != (1, 0):
            x = mul(x, g); n += 1
            if n > 25: return n
        return n

    gen = None
    for a in range(5):
        for b in range(5):
            if (a, b) == (0, 0): continue
            if order((a, b)) == 24:
                gen = (a, b); break
        if gen: break

    # Compute cubic residues: gen^(3k) for k=0..7, plus additive inverses
    cr = set()
    x = (1, 0)
    for _ in range(8):
        cr.add(x)
        cr.add(((-x[0]) % 5, (-x[1]) % 5))  # additive inverse
        x = mul(mul(mul(x, gen), gen), gen)  # x *= gen^3

    # Map elements to integers: (a,b) -> 5a+b
    idx = {(a, b): 5*a+b for a in range(5) for b in range(5)}

    edges = []
    seen = set()
    elems = [(a, b) for a in range(5) for b in range(5)]
    for u in elems:
        for s in cr:
            v = ((u[0]+s[0])%5, (u[1]+s[1])%5)
            i, j = idx[u], idx[v]
            key = (min(i, j), max(i, j))
            if key not in seen and key[0] != key[1]:
                seen.add(key); edges.append(key)
    return edges

def construct(N):
    """10-regular circulant with AP offsets {1,4,7,10,13}: all ≡1 mod 3, diffs ≡0 mod 3 => K4-free."""
    S = [s for s in [1, 4, 7, 10, 13] if s < N // 2 + 1]
    seen = set()
    edges = []
    for i in range(N):
        for s in S:
            for j in [(i + s) % N, (i - s) % N]:
                key = (min(i, j), max(i, j))
                if key not in seen and key[0] != key[1]:
                    seen.add(key); edges.append(key)
    return edges

import random

def construct(N):
    """Start from {2,3,5} circulant, random edge swaps to reduce independence number."""
    random.seed(N * 17 + 3)

    # Build initial {2,3,5} circulant
    adj = [set() for _ in range(N)]
    def add_edge(u, v):
        adj[u].add(v); adj[v].add(u)
    def rem_edge(u, v):
        adj[u].discard(v); adj[v].discard(u)

    for i in range(N):
        for s in [2, 3, 5]:
            j = (i + s) % N
            add_edge(i, j)
            j = (i - s) % N
            add_edge(i, j)

    def is_k4_free_local(u, v):
        """Check if adding edge u-v creates K4."""
        common = adj[u] & adj[v]
        return not any(w in adj[x] for w in common for x in common if w < x)

    def greedy_alpha():
        best = 0
        for _ in range(30):
            order = list(range(N)); random.shuffle(order)
            indep, used = [], set()
            for v in order:
                if v not in used:
                    indep.append(v); used |= adj[v]
            best = max(best, len(indep))
        return best

    alpha = greedy_alpha()
    edges = [(u, v) for u in range(N) for v in adj[u] if u < v]
    import time; t0 = time.time()

    while time.time() - t0 < 3.5:
        # Random edge swap: pick (a,b),(c,d), try swap to (a,c),(b,d)
        (a, b) = random.choice(edges)
        (c, d) = random.choice(edges)
        if len({a, b, c, d}) < 4: continue
        if c in adj[a] or d in adj[b]: continue
        # Swap: remove ab,cd, add ac,bd
        rem_edge(a, b); rem_edge(c, d)
        if is_k4_free_local(a, c) and is_k4_free_local(b, d):
            add_edge(a, c); add_edge(b, d)
            new_alpha = greedy_alpha()
            if new_alpha <= alpha:
                alpha = new_alpha
                edges = [(u, v) for u in range(N) for v in adj[u] if u < v]
            else:
                rem_edge(a, c); rem_edge(b, d)
                add_edge(a, b); add_edge(c, d)
        else:
            add_edge(a, b); add_edge(c, d)

    return [(u, v) for u in range(N) for v in adj[u] if u < v]

def construct(N):
    """Per-N: use Z_p x Z_q Cayley for N=pq, else circulant {2,3,5}."""
    factorizations = {20: (4, 5), 40: (8, 5), 50: (10, 5), 60: (12, 5), 30: (6, 5), 25: (5, 5)}
    if N not in factorizations:
        seen = set()
        edges = []
        for i in range(N):
            for s in [2, 3, 5]:
                for j in [(i+s)%N, (i-s)%N]:
                    key = (min(i,j), max(i,j))
                    if key not in seen and key[0] != key[1]:
                        seen.add(key); edges.append(key)
        return edges

    p, q = factorizations[N]
    # Connection set: (±1,0),(0,±1),(1,1),(-1,-1)
    gens = [(1,0),(p-1,0),(0,1),(0,q-1),(1,1),(p-1,q-1)]
    seen = set()
    edges = []
    for a in range(p):
        for b in range(q):
            u = a*q + b
            for da, db in gens:
                a2, b2 = (a+da)%p, (b+db)%q
                v = a2*q + b2
                key = (min(u,v), max(u,v))
                if key not in seen and key[0] != key[1]:
                    seen.add(key); edges.append(key)
    return edges
